import type { Ref } from 'vue'
import { createContext } from 'reka-ui'

export interface AutocompleteContext {
  searchTerm: Ref<string>
}

const [injectAutocompleteContext, provideAutocompleteContext] =
  createContext<AutocompleteContext>('AutocompleteContext')

export { provideAutocompleteContext }

const requiredKeys: (keyof AutocompleteContext)[] = ['searchTerm']
/**
 * Hook to access the Autocomplete context within sub-components.
 *
 * @returns The shared Autocomplete context.
 * @throws Error if called outside of an `<Autocomplete>` component tree.
 */
export function useAutocompleteContext(): AutocompleteContext {
  const ctx = injectAutocompleteContext()

  if (!ctx) {
    throw new Error(
      '[Autocomplete] useAutocompleteContext() was called outside of an <Autocomplete> component.\n' +
        'Make sure your component is rendered inside an <Autocomplete> root.',
    )
  }
  const missingKeys = requiredKeys.filter(key => ctx[key] === undefined)
  if (missingKeys.length > 0) {
    throw new Error(
      `[Autocomplete] Missing required context property: "${missingKeys.join(', ')}".`,
    )
  }
  return ctx
}

import type { ComboboxRootEmits, ComboboxRootProps } from 'reka-ui'

export type AutocompleteProps = ComboboxRootProps & {
  searchTerm?: string
}

export type AutocompleteEmits = ComboboxRootEmits & {
  'update:searchTerm': [searchTerm: string]
}

import { createContext } from 'reka-ui'
import type { MeterRootContext } from './types'

export const [injectMeterRootContext, provideMeterRootContext] =
  createContext<MeterRootContext>('MeterRootContext')

export const useMeterRootContext = () => {
  const requiredKeys: (keyof MeterRootContext)[] = [
    'variant',
    'size',
    'value',
    'max',
    'min',
    'label',
    'percentage',
    'meterId',
  ]

  const ctx = injectMeterRootContext()
  if (!ctx) {
    throw new Error('[Meter] useMeterRootContext must be used within a MeterRoot')
  }

  const missingKeys = requiredKeys.filter(key => !ctx[key])
  if (missingKeys.length > 0) {
    throw new Error(`[Meter] Missing required context property: "${missingKeys.join(', ')}".`)
  }

  return ctx
}

import { cva } from 'class-variance-authority'

export const meterVariants = cva('relative flex flex-col w-full gap-2')

export const meterTrackVariants = cva(
  'relative w-full overflow-hidden bg-secondary will-change-transform transition-all duration-300 ease-in-out',
  {
    variants: {
      size: {
        sm: 'h-1.5',
        default: 'h-2',
        lg: 'h-3',
      },
    },
    defaultVariants: {
      size: 'default',
    },
  },
)
export const meterIndicatorVariants = cva(
  'absolute h-full left-0 top-0 will-change-[color] transition-all duration-300 ease-in-out',
  {
    variants: {
      variant: {
        default: 'bg-primary',
        success: 'bg-green-500',
        warning: 'bg-yellow-500',
        danger: 'bg-red-500',
      },
    },
    defaultVariants: {
      variant: 'default',
    },
  },
)

export const meterHeaderVariants = cva('flex w-full items-center justify-between')

